+    fn retained_autocommit_indexed_equality_rows_in_txn(
+        &self,
+        cx: &Cx,
+        txn: &mut dyn TransactionHandle,
+        table: &TableSchema,
+        column_index: usize,
+        probe_value: &SqliteValue,
+        rowid_alias_column_index: Option<usize>,
+        projections: Option<&[PreparedMemValueSource]>,
+    ) -> Result<Vec<Row>> {
+        let Some(root) = PageNumber::new(u32::try_from(table.root_page).unwrap_or(0)) else {
+            return Ok(Vec::new());
+        };
+        let mut cursor = Self::new_pager_btree_cursor(cx, txn, root, true)?;
+        let mut rows = Vec::new();
+        if cursor.first(cx)? {
+            loop {
+                let rowid = cursor.rowid(cx)?;
+                let payload = cursor.payload(cx)?;
+                let values = self.decode_table_row_values_from_payload(
+                    table,
+                    rowid,
+                    &payload,
+                    rowid_alias_column_index,
+                )?;
+                let probe_matches = values.get(column_index) == Some(probe_value);
+                if probe_matches {
+                    rows.push(match projections {
+                        Some(projections) => row_from_memdb_value_sources(
+                            rowid,
+                            &values,
+                            projections,
+                            rowid_alias_column_index,
+                        ),
+                        None => Row { values },
+                    });
+                }
+                if !cursor.next(cx)? {
+                    break;
+                }
+            }
+        }
+        Ok(rows)
+    }
